parameters.jsCode:
// Finds the oldest content/queue/*.md file with status: approved, posts its thread to X,
// and returns what happened so the rest of the workflow can archive the file and notify.
// Uses TWO credentials attached to this node: httpHeaderAuth (GitHub PAT - Meal Prep) for
// reading the queue, twitterOAuth1Api (X API - Meal Prep) for posting. See _setup_notes in
// this workflow's export for how to attach both to a single Code node.

const REPO = 'shinyamadasan/Meal-Prep';

function parseFrontmatter(raw) {
  const m = raw.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n([\s\S]*)$/);
  if (!m) return null;
  const fm = {};
  m[1].split(/\r?\n/).forEach((line) => {
    const mm = line.match(/^([a-zA-Z_]+):\s*(.*)$/);
    if (mm) fm[mm[1]] = mm[2].trim();
  });
  return { fm, body: m[2] };
}

// 1. List the queue directory. A truly empty/never-existed directory 404s -- treat that as
//    "nothing to do", not an error, since it just means everything has already been posted.
let listing;
try {
  listing = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
    method: 'GET',
    url: `https://api.github.com/repos/${REPO}/contents/content/queue`,
    headers: { 'Accept': 'application/vnd.github+json', 'User-Agent': 'n8n-meal-prep-poster' },
    json: true,
  });
} catch (e) {
  if (e.httpCode === '404' || e.statusCode === 404) return [{ json: { found: false, reason: 'queue directory empty or missing' } }];
  throw e;
}

const mdFiles = (Array.isArray(listing) ? listing : []).filter((f) => f.name && f.name.endsWith('.md'));

// 2. Fetch each file's raw content and parse its frontmatter. Small number of files expected
//    (a handful of drafts at a time), so a plain sequential loop is fine -- no need for
//    concurrency here.
const candidates = [];
for (const f of mdFiles) {
  const raw = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
    method: 'GET',
    url: f.url,
    headers: { 'Accept': 'application/vnd.github.raw', 'User-Agent': 'n8n-meal-prep-poster' },
  });
  const text = typeof raw === 'string' ? raw : String(raw);
  const parsed = parseFrontmatter(text);
  if (!parsed) continue;
  if ((parsed.fm.status || '').toLowerCase() !== 'approved') continue;
  candidates.push({ path: f.path, sha: f.sha, id: parsed.fm.id || f.name.replace(/\.md$/, ''), source: parsed.fm.source || '', body: parsed.body });
}

if (candidates.length === 0) return [{ json: { found: false, reason: 'no approved drafts in queue' } }];

// content-001, content-002, ... sorts correctly as plain strings -- oldest first.
candidates.sort((a, b) => (a.id > b.id ? 1 : -1));
const next = candidates[0];

// 3. Split the body into individual tweets on a \n---\n delimiter (same convention as this
//    repo's markdown docs using --- as a section break).
const tweets = next.body.trim().split(/\r?\n---\r?\n/).map((t) => t.trim()).filter(Boolean);
if (tweets.length === 0) throw new Error(`content-poster: ${next.id} has status: approved but no tweet text found in its body`);

// 4. Post the thread. Each tweet after the first replies to the one before it. If any call
//    fails partway through, this THROWS -- the workflow's Error Workflow (Telegram alert) fires,
//    and the queue file is left untouched (still status: approved) for a human to check before
//    the next scheduled run retries it. KNOWN LIMITATION: a partial-thread failure (e.g. tweet 4
//    of 9 fails) leaves tweets 1-3 already live on X, and a retry reposts the whole thread from
//    tweet 1 -- rare, but if it happens, check the account and delete the orphaned partial thread
//    by hand before the next scheduled attempt.
const postedIds = [];
let previousId = null;
for (const text of tweets) {
  const body = previousId ? { text, reply: { in_reply_to_tweet_id: previousId } } : { text };
  const res = await this.helpers.httpRequestWithAuthentication.call(this, 'twitterOAuth1Api', {
    method: 'POST',
    url: 'https://api.twitter.com/2/tweets',
    body,
    json: true,
  });
  previousId = res.data.id;
  postedIds.push(previousId);
}

return [{
  json: {
    found: true,
    path: next.path,
    sha: next.sha,
    id: next.id,
    source: next.source,
    body: next.body,
    postedIds,
    firstUrl: `https://x.com/ShinYamadaSan/status/${postedIds[0]}`,
  },
}];

