parameters.jsCode:
// Builds the content/posted/YYYY/MM/<id>.md archive file: original body, frontmatter updated
// to status: posted with posted_at and the actual posted tweet ids for reference.
const d = new Date();
const yyyy = d.getUTCFullYear();
const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
const path = `content/posted/${yyyy}/${mm}/${$json.id}.md`;
const fm = [
  '---',
  `id: ${$json.id}`,
  `source: ${$json.source}`,
  'platform: x',
  'status: posted',
  `posted_at: ${d.toISOString()}`,
  `posted_ids: ${$json.postedIds.join(',')}`,
  '---',
  '',
].join('\n');
const content = fm + $json.body.trim() + '\n';
const contentB64 = Buffer.from(content, 'utf8').toString('base64');
return [{ json: { ...$json, archivePath: path, contentB64 } }];
